 84→    @Operation(summary = "Create Space Node")
 85→    public ResponseData<TreeNode<SpaceNodeVo>> createSpaceNode(@RequestBody @Valid SpaceNodeCreateRo ro) {
 86→        Long userId = SessionContext.getUserId();
 87→        String spaceId = SpaceHolder.get();
 88→        // 鉴权
 89→        if (ro.getParentId() == null ||  ro.getParentId() == 0) {
 90→            // 创建在根节点, 取space默认权限
 91→            permissionChecker.requireUser(userId).onSpaceDefaultNode(spaceId).needPermission(NodePermission.CREATE_NODE);
 92→        } else {
 93→            // 在已有节点下创建, 取父节点权限
 94→            NodeEntity nodeEntity = nodeService.getById(ro.getParentId());
 95→            if (nodeEntity == null) {
 96→                throw new BusinessException(SpaceNodeException.NOT_EXIST);
 97→            }
 98→            permissionChecker.requireUser(userId).onNode(nodeEntity.getRelId()).needPermission(NodePermission.CREATE_NODE);
 99→        }
100→
101→        TreeNode<SpaceNodeVo> result = spaceNodeUpdateManager.createSpaceNode(spaceId, userId, ro);
102→        return ResponseData.success(result);
103→    }
