 22→/**
 23→ * 注意SpaceNode的tag id使用SpaceNodeId（node.data.id）而不是TreeNodeId
 24→ *
 25→ * tags
 26→ * - SpaceNode
 27→ *   - `${spaceNodeId}` 节点信息
 28→ *   - `STAR_LIST` 主页收藏列表
 29→ *   - `LIST-${spaceId}` 空间站文件树
 30→ * - SpaceNodeVersion
 31→ *   - `LIST-${spaceNodeId}` 节点版本列表
 32→ */
 33→export const spaceNodeApi = aioApi.injectEndpoints({
 34→  endpoints: (build) => ({
 35→    queryLastVisitSpaceNodePage: build.infiniteQuery<IPageSpaceNode, void, number>({
 36→      infiniteQueryOptions: {
 37→        initialPageParam: 1,
 38→        getNextPageParam: (_lastPage, _allPages, lastPageParam) => lastPageParam >= 10 ? undefined : lastPageParam + 1,
 39→      },
 40→      query: (data) => ({
 41→        url: 'api/v1/node/visit/queryLastVisitSpaceNodes',
 42→        method: 'POST',
 43→        data: {
 44→          pageNum: data.pageParam,
 45→          pageSize: 20,
 46→        },
 47→      }),
 48→      providesTags: (res) => res
 49→        ? res.pages
 50→            .map((it) => it.records)
 51→            .flat()
 52→            .map((it) => ({ type: 'SpaceNode', id: it.id }))
 53→        : [],
 54→      keepUnusedDataFor: 0,
 55→    }),
 56→    queryStarredSpaceNodes: build.query<IPageSpaceNode, {
 57→      pageNum?: number;
 58→      pageSize?: number;
 59→    }>({
 60→      query: (data) => ({ url: 'api/v1/node/star/queryStarredSpaceNodes', method: 'POST', data }),
 61→      providesTags: (res) => res ? [...res.records.map((it) => ({ type: 'SpaceNode' as const, id: it.id })), { type: 'SpaceNode', id: 'STAR_LIST' }] : [],
 62→    }),
 63→    starSpaceNode: build.mutation<void, string>({
 64→      query: (spaceNodeId) => ({ url: `api/v1/node/star/${spaceNodeId}/starSpaceNode`, method: 'POST' }),
 65→      invalidatesTags: (_res, _err, req) => [{ type: 'SpaceNode', id: req }, { type: 'SpaceNode', id: 'STAR_LIST' }],
 66→    }),
 67→    unstarSpaceNode: build.mutation<void, string>({
 68→      query: (spaceNodeId) => ({ url: `api/v1/node/star/${spaceNodeId}/unstarSpaceNode`, method: 'POST' }),
 69→      invalidatesTags: (_res, _err, req) => [{ type: 'SpaceNode', id: req }, { type: 'SpaceNode', id: 'STAR_LIST' }],
 70→    }),
 71→    getSpaceNodeTree: build.query<{
 72→      tree: ISpaceTreeNode[];
 73→      /** <nodeTree.id, ISpaceTreeNode> */
 74→      treeNodeMap: Record<string, ISpaceTreeNode | undefined>;
 75→      /** <nodeTree.data.id, ISpaceTreeNode> */
 76→      spaceNodeMap: Record<string, ISpaceTreeNode | undefined>;
 77→    }, string, ISpaceTree[]>({
 78→      query: (spaceId) => ({
 79→        url: `api/v1/node/spaceNodeTree`,
 80→        headers: {
 81→          'x-space-id': spaceId,
 82→        },
 83→      }),
 84→      transformResponse: (res) => {
 85→        return resolveSpaceTree(res);
 86→      },
 87→      providesTags: (res, _err, args) => res ? [...Object.keys(res.spaceNodeMap).map((it) => ({ type: 'SpaceNode' as const, id: it })), { type: 'SpaceNode', id: `LIST-${args}` }] : [],
 88→    }),
 89→    moveSpaceNode: build.mutation<void, {
 90→      spaceId: string; nodeId: string; parentId: string; preId: string;
 91→    }>({
 92→      query: ({
 93→        spaceId, nodeId, parentId, preId,
 94→      }) => ({
 95→        url: 'api/v1/node/moveSpaceNode',
 96→        method: 'POST',
 97→        data: {
 98→          nodeId,
 99→          newPreId: preId,
100→          newParentId: parentId,
101→        },
102→        headers: {
103→          'x-space-id': spaceId,
104→        },
105→      }),
106→      invalidatesTags: (_res, _err, req) => [{ type: 'SpaceNode', id: `LIST-${req.spaceId}` }],
107→    }),
108→    batchMoveSpaceNode: build.mutation<void, {
109→      spaceId: string; nodeIds: string[]; newParentId: string; newPreId: string;
110→    }>({
111→      query: ({
112→        spaceId, nodeIds, newParentId, newPreId,
113→      }) => ({
114→        url: 'api/v1/node/batchMoveSpaceNode',
115→        method: 'POST',
116→        data: {
117→          nodeIds,
118→          newPreId,
119→          newParentId,
120→        },
121→        headers: {
122→          'x-space-id': spaceId,
123→        },
124→      }),
125→      invalidatesTags: (_res, _err, req) => [{ type: 'SpaceNode', id: `LIST-${req.spaceId}` }],
126→    }),
127→    relAppSpaceNode: build.mutation<ISpaceTree, {
128→      parentId: string;
129→      name: string;
130→      type: SpaceTreeNodeType;
131→      appSpaceNodeId: string;
132→      spaceId: string;
133→    }>({
134→      query: ({ spaceId, ...data }) => ({
135→        url: 'api/v1/node/relAppSpaceNode',
136→        method: 'POST',
137→        data,
138→        headers: {
139→          'x-space-id': spaceId,
140→        },
141→      }),
142→      invalidatesTags: (_res, _err, req) => [{ type: 'SpaceNode', id: `LIST-${req.spaceId}` }],
143→    }),
144→    updateSpaceNode: build.mutation<ISpaceNode, {
145→      /** spaceNodeId */
146→      id: string;
147→      name: string;
148→      description: string;
149→      spaceId: string;
150→    }>({
151→      query: ({ spaceId, ...data }) => ({
152→        url: 'api/v1/node/updateSpaceNode',
153→        method: 'POST',
154→        data,
155→        headers: {
156→          'x-space-id': spaceId,
157→        },
158→      }),
159→      invalidatesTags: (res) => res ? [{ type: 'SpaceNode', id: res.id }] : [],
160→    }),
161→    batchUpdateSpaceNode: build.mutation<void, {
162→      spaceId: string;
163→      tasks: {
164→        /** spaceNodeId */
165→        id: string;
166→        name: string;
167→        description: string;
168→      }[];
169→    }>({
170→      queryFn: async (arg, _api, _extraOptions, baseQuery) => {
171→        const results = await Promise.all(arg.tasks.map((data) => baseQuery({
172→          url: 'api/v1/node/updateSpaceNode',
173→          method: 'POST',
174→          data,
175→          headers: {
176→            'x-space-id': arg.spaceId,
177→          },
178→        })));
179→        for (const res of results) {
180→          if (res.error) {
181→            return res;
182→          }
183→        }
184→        return { data: undefined };
185→      },
186→      invalidatesTags: (_res, err, args) => err ? [] : args.tasks.map((it) => ({ type: 'SpaceNode' as const, id: it.id })),
187→    }),
188→    updateNextCloudNode: build.mutation<ISpaceNode, {
189→      /** spaceNodeId */
190→      fileId: string;
191→      versionId: string;
192→      versionName: string;
193→      spaceId: string;
194→    }>({
195→      query: ({ spaceId, ...data }) => ({
196→        url: 'api/v1/nextcloud/version/name',
197→        method: 'POST',
198→        data,
199→        headers: {
200→          'x-space-id': spaceId,
201→        },
202→      }),
203→      invalidatesTags: (res) => res ? [{ type: 'SpaceNode', id: res.id }] : [],
204→    }),
205→    deleteSpaceNode: build.mutation<void, { spaceNodeId: string; spaceId: string }>({
206→      query: ({ spaceNodeId, spaceId }) => ({
207→        url: `api/v1/node/${spaceNodeId}/deleteSpaceNode`,
208→        headers: {
209→          'x-space-id': spaceId,
