248→/** 树节点变更ws事件（`TREE_NODE_CHANGED`）类型 */
249→export enum TreeNodeChangedMessageAction {
250→  /** 节点新增 */
251→  ADDED = 'ADDED',
252→  /** 批量移动 */
253→  BATCH_MOVED = 'BATCH_MOVED',
254→  /** 节点删除 */
255→  DELETED = 'DELETED',
256→}
257→
258→interface ITreeNodeChangedMessagePayloadMap {
259→  [TreeNodeChangedMessageAction.ADDED]: {
260→    /** 树节点 `SpaceTreeNode.id` */
261→    nodeId: string;
262→    /** 父节点 `SpaceTreeNode.id`，根节点为 '0' */
263→    parentId: string;
264→    /** 关联的 `SpaceNode.id` */
265→    relId: string;
266→  };
267→  [TreeNodeChangedMessageAction.BATCH_MOVED]: {
268→    /** 批量移动后的新父节点 `SpaceTreeNode.id` */
269→    newParentId: string;
270→    /** 被移动的节点列表 */
271→    movedNodes: {
272→      /** 树节点 `SpaceTreeNode.id` */
273→      nodeId: string;
274→      /** 关联的 `SpaceNode.id` */
275→      relId: string;
276→      /** 移动前的父节点 `SpaceTreeNode.id` */
277→      oldParentId: string;
278→    }[];
279→  };
280→  [TreeNodeChangedMessageAction.DELETED]: {
281→    /** 被删除的树节点 `SpaceTreeNode.id` */
282→    nodeId: string;
283→    /** 删除前的父节点 `SpaceTreeNode.id`，根节点为 `0` */
284→    parentId: string | number;
285→    /** 节点名称（仅用于展示或降级处理） */
286→    nodeName: string;
287→    /** 关联的 `SpaceNode.id` */
288→    relId: string;
289→  };
290→}
291→
292→/** 树结构相关的新增 / 批量移动 / 删除事件 */
293→export interface ITreeNodeChangedMessage<T extends TreeNodeChangedMessageAction = TreeNodeChangedMessageAction> {
294→  /** 变更动作 */
295→  action: TreeNodeChangedMessageAction;
296→  /** 树标识 */
297→  treeId: string;
298→  /** 事件 traceId，可用于串联后端日志 */
299→  traceId: string;
300→  /** 触发操作的用户 id（若有登录态） */
301→  operatorId: string;
302→  /** 事件触发来源：`WEB`（用户在网页端操作）/ `NEXTCLOUD_WEBHOOK`（云盘同步触发）等 */
303→  eventTriggerSource: string;
304→  /** 推送时间（毫秒时间戳） */
305→  timestamp: number;
306→  payload: ITreeNodeChangedMessagePayloadMap[T];
307→}
308→export function isTreeNodeChangedMessageType<T extends TreeNodeChangedMessageAction>(
309→  message: ITreeNodeChangedMessage,
310→  type: T,
311→): message is ITreeNodeChangedMessage<T> {
312→  return message.action === type;
313→}
